3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	};
7	
8	const FIRST_INSURANCE_PERCENT = 110;
9	const PROCESSING_FEE = 5;
10	
11	export function processScenario(scenario: any): unknown {
12	  const step = scenario.steps[0];
13	  const itemsBaseTotal = step.items.reduce(
14	    (total: number, item: { type: string }) => total + BASE_PREMIUMS[item.type],
15	    0,
16	  );
17	  const premium = (itemsBaseTotal * FIRST_INSURANCE_PERCENT) / 100 + PROCESSING_FEE;
18	  return { results: [{ premium }] };
19	}
